INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (1, 1, "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 190804, "カリン", 60000, 0, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (2, 1, "今日の運勢は姫吉！　あらゆる運気が最大を示しています！　　　今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！", 0, "", 60000, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (3, 1, "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 0, "", 60000, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (4, 2, "今日の運勢は姫吉！　その高い運気はまさにショーグンの如く！　その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！", 0, "", 60000, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (5, 1, "今日の運勢は大吉！　運気がどんどん高まっています！　　　　　何をやっても、最大効率で素晴らしい結果になりますよ♪", 0, "", 60000, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (6, 1, "今日の運勢は大吉！　なにをやっても上手くいって大活躍！　　　そんな素敵なあなたを見て、後ろから誰かが……クスクス♪", 0, "", 60000, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (7, 2, "今日の運勢は大吉！　運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！　目指せヒデサ……ではなく秀才！", 0, "", 60000, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (8, 1, "今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたいやき！　和菓子パワーで売上アップです！", 0, "", 60000, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (9, 1, "今日の運勢は中吉！　旅行運がぐんぐんと上昇中♪　　　　　　　もしかしたら、あの「マホマホ王国」にだって行けるかも♪", 0, "", 60000, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (10, 1, "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 0, "", 60000, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (11, 1, "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 0, "", 60000, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (12, 2, "今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪", 0, "", 60000, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (13, 1, "今日の運勢は小吉！　早朝に幸運の兆しあり！　　　　　　　　　もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪", 0, "", 60000, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (14, 1, "今日の運勢は小吉！　運気上昇中ですが、上がるまでが要注意！　ラッキーアニマルは熊！　本当の家族のように守ってくれるかも♪", 0, "", 60000, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (15, 1, "今日の運勢は小吉！　外に出てゆっくり過ごすと運気が上昇！　　ラッキースポットは牧場。面白い出会いがありそうです♪", 0, "", 60000, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (16, 1, "今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", 0, "", 60000, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (17, 2, "今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", 0, "", 60000, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (18, 0, "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 190804, "カリン", 60000, 0, 0, "", 2, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (19, 0, "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 190804, "カリン", 60000, 7, 0, "", 3, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (20, 0, "キミと出会ってもう\n1年もたつんだね！\nう～ん、いつも\n寝てばっかりだから、", 101201, "ハツネ", 80001, 1, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (21, 0, "少しでも\n寝る時間を減らして\nキミと一緒にいる\n時間増やしたいなぁ♪", 101201, "ハツネ", 80001, 1, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (22, 0, "あなたと知り合ってから\nもう1年…\n時がたつのは\n早いですね", 103801, "シオリ", 80001, 1, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (23, 0, "来年も、\n一緒にいられたら…\nうれしいな", 103801, "シオリ", 80001, 1, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (24, 0, "あなたと一緒にいるようになって、\nもう1年ですか…", 103601, "キョウカ", 80001, 2, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (25, 0, "最初の頃よりも、頼もしく\nなりましたね。私はどうですか？\n成長していますか？", 103601, "キョウカ", 80001, 2, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (26, 0, "おにいちゃんとあってから、\n1年たったよ～！", 102001, "ミミ", 80001, 2, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (27, 0, "ミミね、おにいちゃんと\nいっぱい遊べてたのしかったな～♪\nこれからもずっと\nいっしょにいてね～！", 102001, "ミミ", 80001, 2, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (28, 0, "にいちゃんがミソギのイタズラに\n引っかかり続けてもう1年かぁ", 100401, "ミソギ", 80001, 2, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (29, 0, "…これからもいっぱいミソギと\n遊んでね、にいちゃん！", 100401, "ミソギ", 80001, 2, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (30, 0, "もう王子はんと会うてから\n1年ぐらいたつそうどすえ\n早いもんやなあ", 101001, "マホ", 80001, 3, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (31, 0, "このままやと、\nうちもあっという間に\n干からびてしまいそうどすえ\nなーんてな。うふふ", 101001, "マホ", 80001, 3, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (32, 0, "お主と会って早1年じゃな\nこれからも存分に尽くすがよい", 104401, "イリヤ", 80001, 3, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (33, 0, "わらわもたまには、お主の献身に\n報いてやらぬでもない♪", 104401, "イリヤ", 80001, 3, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (34, 0, "もう、キミと出会って結構な時間が\nたつさ～。でも、私たちの旅は\nまだまだ始まったばかりさ～！", 101701, "カオリ", 80001, 3, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (35, 0, "これからも、どうぞよろしく\nお願いするさ～！", 101701, "カオリ", 80001, 3, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (36, 0, "あんたと出会ってからもうそんなに\nたつのね～", 102801, "サレン", 80001, 4, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (37, 0, "あっという間だったって感じるほど\n楽しかったわ！\nこれからも一緒に頑張りましょ！", 102801, "サレン", 80001, 4, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (38, 0, "出会ってから1年間、ずっと\nご迷惑をかけっぱなしで、\nすみません…", 102501, "スズメ", 80001, 4, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (39, 0, "これからはもっと頑張りますから\n見ていてくださいね\nできれば…\n今までよりも、私の近くで♪", 102501, "スズメ", 80001, 4, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (40, 0, "振り返れば、今までいろんなことが\nあったにゃあ…", 104601, "タマキ", 80001, 5, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (41, 0, "これからも、二人でたくさんの\n思い出をがっぽり作っていく\nにゃー！", 104601, "タマキ", 80001, 5, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (42, 0, "キミとの師弟関係も、\nもう1年なのね…\nでもキミに教えることは、", 104801, "ミフユ", 80001, 5, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (43, 0, "まだまだいっぱいあるわ\nこれからも、\nしっかりついて来てね！", 104801, "ミフユ", 80001, 5, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (44, 0, "あなたさまと出会ってもう1年…", 103201, "アキノ", 80001, 6, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (45, 0, "光陰矢のごとし、とはまさに\nこのことですわ。…思い出は決して\nお金では買えませんわね", 103201, "アキノ", 80001, 6, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (46, 0, "ダメな私を1年間も見捨てないで\nくれて、本当にありがとう", 103401, "ユカリ", 80001, 6, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (47, 0, "情けないところいっぱいみせるかも\nしれないけど、これからも一緒に\nいてくれると、うれしいな", 103401, "ユカリ", 80001, 6, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (48, 0, "オマエと出会ってもう1年か\nまさかこのワタシの結婚相手に\nなろうとはな…", 107101, "クリスティーナ", 80001, 7, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (49, 0, "ともかくこれからも\n愉しませてくれよ☆", 107101, "クリスティーナ", 80001, 7, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (50, 0, "君と出会ってからもう1年か。\n以前と比べて私の表情もいくらか\n柔らかくなった気がするんだが、\nどうだろう？", 104701, "ジュン", 80001, 7, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (51, 0, "見えないから分からないって？\nそれもそうだな…", 104701, "ジュン", 80001, 7, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (52, 0, "もう1年たったみたいだね\nあなたをからかってばかりだった\nけど、楽しかった♪", 103701, "トモ", 80001, 8, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (53, 0, "これからもよろしくね！", 103701, "トモ", 80001, 8, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (54, 0, "出会って、もう1年たっちゃった\nんスね。なんだか意外ッス", 100501, "マツリ", 80001, 8, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (55, 0, "毎日楽しくて、あっという間に過ぎ\nちゃったみたいなんスよね\nこれからも一緒に悪と戦うッス！", 100501, "マツリ", 80001, 8, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (56, 0, "オマエと会って1年なの！\n全然成仏もできなかったし、", 100701, "ミヤコ", 80001, 9, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (57, 0, "生き返りもしなかったけど、\nすごく楽しかったの～♪\nオマエとプリンがあれば、\nミヤコはハッピーなの～♪", 100701, "ミヤコ", 80001, 9, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (58, 0, "あなたと出会って1年なんですね\nでも、私の占いでは、私とあなたは", 103101, "シノブ", 80001, 9, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (59, 0, "来年も再来年も一緒にいるようです\nふふ、よろしくお願いしますね", 103101, "シノブ", 80001, 9, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (60, 0, "貴様が閃光のシグルドとして覚醒し\nもう1年か…。これからも我らの\n長き戦いに終わりはないが、", 100901, "アンナ", 80001, 10, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (61, 0, "それでも貴様となら…\n添い遂げる覚悟はできているぞ！", 100901, "アンナ", 80001, 10, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (62, 0, "君と出会ってもう1年だって！\n早いねー！", 101301, "ナナカ", 80001, 10, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (63, 0, "これからも最強のバディタッグで\n大活躍だー！\n頼りにしてるよ、相棒！", 101301, "ナナカ", 80001, 10, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (64, 0, "1年たつのって、あっという間ね\nまだまだ君の知らない部分が\nたくさんあるし…", 105101, "ミツキ", 80001, 11, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (65, 0, "これからも、いろんなところを\n調べさせてね？", 105101, "ミツキ", 80001, 11, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (66, 0, "お前さんと出会ってもう1年か\n助太刀するつもりが", 105601, "ルカ", 80001, 11, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (67, 0, "逆に助けられたりもしたね\nこれからもよろしく頼むよ！", 105601, "ルカ", 80001, 11, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (68, 0, "早いものですわね、あなた様と\nお会いして、もう1年…", 102701, "エリコ", 80001, 11, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (69, 0, "あなた様といると、時があっと\nいう間に過ぎてしまいます\n時間を止める研究をしなくては\nいけませんね…", 102701, "エリコ", 80001, 11, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (70, 0, "お兄ちゃんと会ってから、もう、\n1年なんだね。私、少しは\nお姉ちゃんっぽくなったかな？", 102301, "アヤネ", 80001, 12, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (71, 0, "あ、ぷうきちもお兄ちゃんっぽく\nなったよね？", 102301, "アヤネ", 80001, 12, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (72, 0, "あなたと出会って、\nもう1年がたったんですね…\nこれからもそばにいて、", 104201, "チカ", 80001, 12, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (73, 0, "私のことを見守ってください\nできることなら、ずっと…", 104201, "チカ", 80001, 12, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (74, 0, "お兄ちゃんと出会って1年かぁ\n私、相変わらずダメダメで…", 102101, "クルミ", 80001, 12, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (75, 0, "で、でもこれからもずっと…\n一緒にいたいなぁ…", 102101, "クルミ", 80001, 12, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (76, 0, "再会してちょうど1年だね\nお祝いにごちそう作ってきたよ～♪\n特製ケーキと、お寿司と、", 104901, "シズル", 80001, 13, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (77, 0, "ハンバーグと、カレーと、\nシチューと、あ、隠しきれない隠し\n味は、お姉ちゃんの愛情だよ！", 104901, "シズル", 80001, 13, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (78, 0, "お兄ちゃんと再会して、もう1年\nなんですね。\n会えなかった時を思うと、", 101101, "リノ", 80001, 13, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (79, 0, "信じられないくらい幸せな1年\nでした！もう絶対、私から離れ\nないでくださいね♪", 101101, "リノ", 80001, 13, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (80, 0, "騎士クンと出会ってから今まで、\nいろんなことがあったよね\n楽しいこと、ドキドキしたこと…", 100201, "ユイ", 80001, 14, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (81, 0, "そんな日々をこれからも、\nず、ずっと一緒に…\n過ごしていきたいな…！", 100201, "ユイ", 80001, 14, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (82, 0, "騎士くんと出会って、まだ1年しか\nたってないんだ！？", 100101, "ヒヨリ", 80001, 14, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (83, 0, "なんかもうずっと一緒にいる気が\nするなぁ…えへへ。これからの\n1年もまたよろしくねっ！\n騎士くん！", 100101, "ヒヨリ", 80001, 14, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (84, 0, "初めてキミに出会って1年…\n随分見違えたね私もキミも、\n更に強くなっていく…", 100301, "レイ", 80001, 14, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (85, 0, "キミに背中を預けられる日が、\n早くきますように", 100301, "レイ", 80001, 14, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (86, 0, "1年もわたしのことを、忘れない\nでいてくれて、ありがとうござい\nます！", 105801, "ペコリーヌ", 80001, 15, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (87, 0, "これからもずっと、覚えていて\nくださいね！", 105801, "ペコリーヌ", 80001, 15, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (88, 0, "こうして1年も、主さまのおそばに\n置いていただけて、とても光栄\nです。どうかこれからも、", 105901, "コッコロ", 80001, 15, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (89, 0, "末永く主さまをお世話させて\nください。わたくしは、ずっと\n主さまのガイド役でいたいのです", 105901, "コッコロ", 80001, 15, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (90, 0, "1年か、まっさかこんなに長い\n付き合いになるなんてね～\nでも…わりと楽しい1年だったかも", 106001, "キャル", 80001, 15, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (91, 0, "だから、もうしばらくあんたに\n付き合ってやるわよ喜びなさい！", 106001, "キャル", 80001, 15, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (92, 1, "新しい年のはじめに、\nおみくじはいかがでしょうか？\nよい運勢であるほど、\n沢山プレゼントが貰えますよ♪", 112101, "スズメ", 60001, 0, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (93, 1, "今日の運勢は姫吉！　あらゆる運気が最大を示しています！　　　今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！", 0, "", 60001, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (94, 1, "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 0, "", 60001, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (95, 1, "今日の運勢は姫吉！　最強の運勢でどんなドジも跳ね除けます！　大切な人と一緒に、最高の一日になること間違いなし！", 0, "", 60001, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (96, 1, "今日の運勢は姫吉！　どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！　新しい一歩を踏み出そう！", 0, "", 60001, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (97, 2, "今日の運勢は姫吉！　その高い運気はまさにショーグンの如く！　その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！", 0, "", 60001, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (98, 1, "今日の運勢は大吉！　運気がどんどん高まっています！　　　　　何をやっても、最大効率で素晴らしい結果になりますよ♪", 0, "", 60001, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (99, 1, "今日の運勢は大吉！　なにをやっても上手くいって大活躍！　　　そんな素敵なあなたを見て、後ろから誰かが……クスクス♪", 0, "", 60001, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (100, 1, "今日の運勢は大吉！　ラッキーワードは「ちぇる～ん♪」　　　　出会う人みんなに言ってあげると、ハッピーになれますよ！", 0, "", 60001, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (101, 1, "今日の運勢は大吉！　運勢はバッチリで無敵状態！　　　　　　　龍眼で全てを見通して、思い通りの一日を過ごしましょう！", 0, "", 60001, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (102, 2, "今日の運勢は大吉！　運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！　目指せヒデサ……ではなく秀才！", 0, "", 60001, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (103, 1, "今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたいやき！　和菓子パワーで売上アップです！", 0, "", 60001, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (104, 1, "今日の運勢は中吉！　旅行運がぐんぐんと上昇中♪　　　　　　　もしかしたら、あの「マホマホ王国」にだって行けるかも♪", 0, "", 60001, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (105, 1, "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 0, "", 60001, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (106, 1, "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 0, "", 60001, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (107, 1, "今日の運勢は中吉！　お出かけした先で良縁に恵まれそうです！　ダウナー系あざとい女子が、あま～い飴をくれるかも？", 0, "", 60001, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (108, 1, "今日の運勢は中吉！　大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！", 0, "", 60001, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (109, 2, "今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪", 0, "", 60001, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (110, 1, "今日の運勢は小吉！　早朝に幸運の兆しあり！　　　　　　　　　もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪", 0, "", 60001, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (111, 1, "今日の運勢は小吉！　運気上昇中ですが、上がるまでが要注意！　ラッキーアニマルは熊！　本当の家族のように守ってくれるかも♪", 0, "", 60001, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (112, 1, "今日の運勢は小吉！　外に出てゆっくり過ごすと運気が上昇！　　ラッキースポットは牧場。面白い出会いがありそうです♪", 0, "", 60001, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (113, 1, "今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", 0, "", 60001, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (114, 1, "今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", 0, "", 60001, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (115, 1, "今日の運勢は小吉！　思わぬ相手と仲良くなれるかも？　　　　　うっかり毒舌をもらしてしまわないように要注意です！", 0, "", 60001, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (116, 2, "今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", 0, "", 60001, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (117, 0, "おみくじの結果はいかがでしたか？\n新たに始まる一日が、\nあなたにとってよい日になりますように\n明日もお待ちしていますね♪", 112101, "スズメ", 60001, 0, 0, "", 2, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (118, 0, "おみくじ、楽しんで頂けましたか？\nあなたの新しい年が\n素晴らしいものになるよう、\n心からお祈りしますね", 112101, "スズメ", 60001, 7, 0, "", 3, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (119, 0, "ヒューヒュー♪\nドンドンパフパフー♪", 105801, "ペコリーヌ", 80003, 1, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (120, 0, "ひゅーひゅー\nどんどんぱふぱふー\nでございます", 105901, "コッコロ", 80003, 1, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (121, 0, "さぁ、キャルさまもご一緒に\nどんどんぱふぱふいたしましょう", 105901, "コッコロ", 80003, 1, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (122, 0, "え？　ちょっと\nいきなりなにっ？", 106001, "キャル", 80003, 1, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (123, 0, "ドンドンパフパフってなんなの？\nあたしにも分かるように\nちゃんと説明しなさいっての！", 106001, "キャル", 80003, 1, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (124, 0, "実はですねキャルちゃん！\nもうすぐわたしたちにとっての\n大切な節目──", 105801, "ペコリーヌ", 80003, 1, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (125, 0, "『プリンセスコネクト！\nRe:Dive』\n2.5周年なんですよ！\nやばいですね☆", 105801, "ペコリーヌ", 80003, 1, 0, "", 3, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (126, 0, "ですからその日に向けて\n今から気分を盛り上げているのです", 105901, "コッコロ", 80003, 1, 0, "", 3, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (127, 0, "ああ、そういえば\nそんな時期だっけ\nって言っても、もう少し先じゃない\n気が早いんじゃないの？", 106001, "キャル", 80003, 1, 0, "", 3, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (128, 0, "いいえ、キャルさま\nこういったお祝いは準備から\n楽しむものでございます\nそうですよね、ペコリーヌさま", 105901, "コッコロ", 80003, 1, 0, "", 4, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (129, 0, "その通りです♪　というわけで！\nカウントダウンの始まりですよ！\nみんなで一緒に2.5周年に向けて\n盛り上がっていきましょー☆", 105801, "ペコリーヌ", 80003, 1, 0, "", 4, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (130, 0, "ド、ドンドンパフパフ～\nって何言わせんのよ！\nまったくもう、浮かれちゃってさ", 106001, "キャル", 80003, 1, 0, "", 4, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (131, 0, "ふふ。キャルさまもワクワクして\nおいでのようですね\nそれでは主さま。大切な記念日まで\nどうぞご期待くださいませ", 105901, "コッコロ", 80003, 1, 0, "", 5, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (132, 0, "記念日を盛り上げるったって\n一体どうしたらいいのよ？\nあたし、そういうの\n苦手なんだけど…", 106001, "キャル", 80003, 2, 0, "", 5, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (133, 0, "あら、キャルさん\nどうかなさいましたか？\n何かお困りのようですけど", 190801, "カリン", 80003, 2, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (134, 0, "げっ…カリンじゃない\nなんでもないわよ！", 106001, "キャル", 80003, 2, 0, "", 6, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (135, 0, "そうなのですか？\nキャルさんのことですからてっきり\n2.5周年をどう盛り上げたら\nいいか悩んでいるのかと…", 190801, "カリン", 80003, 2, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (136, 0, "分かってんじゃないのよ！？\nいっ、いや、違うけどね！\nあたしは別にそんなことで\n悩んでないわよっ？", 106001, "キャル", 80003, 2, 0, "", 7, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (137, 0, "ふふっ…\nこういう時は、真心を込めて\n気持ちをそのまま口にしたら\nいいのではないでしょうか？", 190801, "カリン", 80003, 2, 0, "", 3, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (138, 0, "気持ちを、ねぇ\nそれが一番難しいんじゃない…\nそもそも、あたしは記念日とか\n別にどうだっていいし", 106001, "キャル", 80003, 2, 0, "", 8, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (139, 0, "…まあ、ペコリーヌもコロ助も\nやけに楽しそうだったから…\nこういうお祭り騒ぎみたいなのも\nたまにはいいかな、とは思うけど", 106001, "キャル", 80003, 2, 0, "", 9, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (140, 0, "なるほどなるほど～\nキャルさんは【美食殿】で祝う\n2.5周年を心から楽しみに\nしている、ということですね！", 190801, "カリン", 80003, 2, 0, "", 4, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (141, 0, "はぁ！？\nどこ聞いたらそうなるのよ！\nあたしは別に楽しみになんか…！", 106001, "キャル", 80003, 2, 0, "", 10, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (142, 0, "キャルさんの心からの想い\nみなさんにも伝わったでしょうか？\n私も2.5周年が楽しみです！\n以上、カリンがお伝えしました！", 190801, "カリン", 80003, 2, 0, "", 5, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (143, 0, "心からの想いって何なのよ！？\n勝手に人の言葉を\n捻じ曲げんじゃないわよ！\nこのくそ眼鏡ーーーっ！", 106001, "キャル", 80003, 2, 0, "", 11, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (144, 0, "ペコリーヌさま、もうすぐ\n記念日でございますね\nこういった節目というのは\n感慨深いものでございます", 105901, "コッコロ", 80003, 3, 0, "", 6, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (145, 0, "色んな思い出が蘇ってきますね！\n楽しい出来事が\nいっぱいありました♪", 105801, "ペコリーヌ", 80003, 3, 0, "", 5, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (146, 0, "はい、そうでございますね\n主さまも【美食殿】の活動の他にも\nいろんなご経験をされたと\n聞いておりますよ", 105901, "コッコロ", 80003, 3, 0, "", 7, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (147, 0, "たしか…ランドソルで話題沸騰と\nなっていた、魔法少女なるものに\nお会いになられたとか", 105901, "コッコロ", 80003, 3, 0, "", 8, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (148, 0, "魔法少女って、あの美味しくって\n栄養たっぷりの大ヒット商品\n『魔法少女ソーセージ』の箱に\n描いてある女の子のことですか！？", 105801, "ペコリーヌ", 80003, 3, 0, "", 6, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (149, 0, "あのソーセージ\n美味しいんですよね～♪\nわたしもたっくさん食べてますよ！", 105801, "ペコリーヌ", 80003, 3, 0, "", 7, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (150, 0, "あとは、牧場に素敵な温泉が\n出来たとか…", 105901, "コッコロ", 80003, 3, 0, "", 9, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (151, 0, "牧場ですか！？　温泉につかって\nチーズもオツですね～♪　考えた\nだけでよだれが出ちゃいそうです！\nやばいですね☆", 105801, "ペコリーヌ", 80003, 3, 0, "", 8, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (152, 0, "ペコリーヌさま\n言ってるそばからよだれが…\n今お拭きしますね。ふき、ふき", 105901, "コッコロ", 80003, 3, 0, "", 10, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (153, 0, "えへへ、ありがとうございます\nコッコロちゃん！", 105801, "ペコリーヌ", 80003, 3, 0, "", 9, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (154, 0, "それにしても、主さまは\n【美食殿】の一員として様々な\n美食と出会われていたのですね\nわたくし、感服いたしました", 105901, "コッコロ", 80003, 3, 0, "", 11, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (155, 0, "これからもたくさん冒険をして\nめいっぱい美食を\n味わい尽くしましょうね！", 105801, "ペコリーヌ", 80003, 3, 0, "", 10, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (156, 0, "2.5周年カウントダウン♪\nキャルちゃんキャルちゃん！\nわくわくしますね☆", 105801, "ペコリーヌ", 80003, 4, 0, "", 11, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (157, 0, "あぁもう、うるさいわね～\nまだまだ先でしょ？\nちょっとは落ち着きなさいよ", 106001, "キャル", 80003, 4, 0, "", 12, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (158, 0, "キャルちゃんだって最近\nソワソワしてるじゃないですか～\nさっきもご機嫌そうに鼻歌とか\n歌ってましたよね？", 105801, "ペコリーヌ", 80003, 4, 0, "", 12, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (159, 0, "なっ…！　き、聞いてたの！？\nじゃない、歌ってないわよ！？\nあんたいい加減なこと言うと\nぶっ殺すわよ！？", 106001, "キャル", 80003, 4, 0, "", 13, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (160, 0, "えっへへ～♪\nわたしは最近のキャルちゃんが\nもっともっと大好きですよ♪\nすごく積極的になりましたよね！", 105801, "ペコリーヌ", 80003, 4, 0, "", 13, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (161, 0, "…積極的？\nなんの話よ？", 106001, "キャル", 80003, 4, 0, "", 14, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (162, 0, "またまた～♪\nアイドルを目指そうとしたこと\n忘れちゃったんですか？", 105801, "ペコリーヌ", 80003, 4, 0, "", 14, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (163, 0, "ムーサの町で\nきゃるきゃる～ん☆　って！", 105801, "ペコリーヌ", 80003, 4, 0, "", 15, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (164, 0, "あっ…！？　ちちち違うわよっ！\nあれは操られてただけで\nあたしはアイドルなんか\n目指してないっての！！", 106001, "キャル", 80003, 4, 0, "", 15, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (165, 0, "本当に本当ですか？\nわたし、キャルちゃんとっても\n乗り気だなって\n思ってたんですけど～", 105801, "ペコリーヌ", 80003, 4, 0, "", 16, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (166, 0, "まぁ、悪くはなかったけど…って\nだ、だから目指してないって\n言ってるでしょ！！\nなんてこと思い出させんのよ！？", 106001, "キャル", 80003, 4, 0, "", 16, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (167, 0, "ああ…ダメだわ…\nもう殺すしかない…\n2.5周年が来る前に\n記憶ごと消し去ってやるー！", 106001, "キャル", 80003, 4, 0, "", 17, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (168, 0, "2.5周年まであと10日…\nふ～ん？\n案外早いもんね？", 106001, "キャル", 80003, 5, 0, "", 18, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (169, 0, "そうでございますね…\nその日のためにやるべきことは\nまだまだございます\n気を引き締めねばなりません…！", 105901, "コッコロ", 80003, 5, 0, "", 12, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (170, 0, "やる気十分ねコロ助…\nそんな気負ってるとしんどいわよ？\nお気楽にやりましょ？", 106001, "キャル", 80003, 5, 0, "", 19, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (171, 0, "キャルさま…\nありがとうございます\nキャルさまは本当に\n優しいおかたです", 105901, "コッコロ", 80003, 5, 0, "", 13, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (172, 0, "な、なにわけの分かんないこと\n言ってんのよ…\nあたしは優しくなんかないっての", 106001, "キャル", 80003, 5, 0, "", 20, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (173, 0, "そんなことはございません\n…あの、実はわたくし\nキャルさまに\nひとつお願いがございまして", 105901, "コッコロ", 80003, 5, 0, "", 14, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (174, 0, "お願い？　珍しいわね\nコロ助がそんなこと言うなんて\n…まあ、あたしに出来ることなら\n別にいいけど", 106001, "キャル", 80003, 5, 0, "", 21, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (175, 0, "ありがとうございます\n実は記念日へ向けて\n『かくし芸』というものを\n用意してみようかと思いまして", 105901, "コッコロ", 80003, 5, 0, "", 15, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (176, 0, "かくし芸？", 106001, "キャル", 80003, 5, 0, "", 22, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (177, 0, "はい。きゃるきゃる～ん☆　を\n参考に、ころころ～ん☆　という\nご挨拶を考えてみたのですが\nポーズがうまくいかなくて…", 105901, "コッコロ", 80003, 5, 0, "", 16, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (178, 0, "～～！！　ちょっと褒められて\nいい気になって損したわ！！\nふざけんなふざけんな\nふ～ざ～け～ん～な～っ！！", 106001, "キャル", 80003, 5, 0, "", 23, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (179, 0, "あと９日！　もうすぐですよ♪\nえへへ、楽しみで楽しみで\nごはんが進みますね☆", 105801, "ペコリーヌ", 80003, 6, 0, "", 17, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (180, 0, "ごはんが進みますね☆\nじゃなーい！\nいくらなんでも食べ過ぎよ！\n記念日、迎えられなくなるわよ！？", 106001, "キャル", 80003, 6, 0, "", 24, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (181, 0, "大丈夫ですよキャルさま\n食事はわたくしたちの\n歩んできた道そのもの\nなのですから", 105901, "コッコロ", 80003, 6, 0, "", 17, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (182, 0, "さっすがコッコロちゃん\nいいことを言いますね！\nそう、わたしたち\n【美食殿】の活動目的は─", 105801, "ペコリーヌ", 80003, 6, 0, "", 18, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (183, 0, "─みんなで楽しく食事をすること\nでしょ？\nあれだけ食べ歩いてきたんだから\n分かってるわよ", 106001, "キャル", 80003, 6, 0, "", 25, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (184, 0, "はい…そうでございますね♪\nそれにしてもわたくしたち\n本当にいろいろなものを\n食べ歩いてきましたね…", 105901, "コッコロ", 80003, 6, 0, "", 18, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (185, 0, "そうね…ほんっとうにね…\n毒まみれのニセドラゴンとか\n恐竜…は逃げられちゃったっけ\nあとワニゴ…ワニの魔物とかね", 106001, "キャル", 80003, 6, 0, "", 26, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (186, 0, "そして、とうとう本物の\nドラゴンまで相手に\nしちゃったのよね、あたしたちって", 106001, "キャル", 80003, 6, 0, "", 27, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (187, 0, "信じられない強さだったわね\nあのドラゴン…やっぱり\n作戦はしっかり立てていかないと\nダメよね", 106001, "キャル", 80003, 6, 0, "", 28, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (188, 0, "えへへ…☆\nキャルちゃんが色んなことを\n覚えていてくれて\nうれしいです♪", 105801, "ペコリーヌ", 80003, 6, 0, "", 19, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (189, 0, "わたくしも鮮明に覚えておりますよ\n主さまもきっと…♪", 105901, "コッコロ", 80003, 6, 0, "", 19, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (190, 0, "あったり前でしょ！\n忘れないわよ、あんな滅茶苦茶な\nものばかり食べさせられて！\n…忘れられるわけ、ないじゃない", 106001, "キャル", 80003, 6, 0, "", 29, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (191, 0, "ねえちょっと、ちょっと待って！？\nカリンから、2.5周年記念の\n生放送に出演してほしいって\n言われたんだけど！", 106001, "キャル", 80003, 7, 0, "", 30, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (192, 0, "なんでそういう大事なことを\n急に言うわけ！？\nそんなの聞いてないわよ～！？", 106001, "キャル", 80003, 7, 0, "", 31, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (193, 0, "いっぱい人に見られちゃうのよね？\nなんであたしがそんなこと…", 106001, "キャル", 80003, 7, 0, "", 32, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (194, 0, "あー\nあー\n…声、これで大丈夫かしら？", 106001, "キャル", 80003, 7, 0, "", 33, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (195, 0, "聞き取りにくいかもしれないわね…\nもうちょっと明るい方がいいかも\nえっと…こんな感じ？", 106001, "キャル", 80003, 7, 0, "", 34, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (196, 0, "オイッスー☆", 106001, "キャル", 80003, 7, 0, "", 35, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (197, 0, "……\nいや、ないわ\nいつもどおりが一番ね、うん", 106001, "キャル", 80003, 7, 0, "", 36, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (198, 0, "もう、記念の生放送なんて\n超責任重大なやつじゃない…\nもしなにか失敗とかしたら…", 106001, "キャル", 80003, 7, 0, "", 37, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (199, 0, "ど、どど、どうしよう！？\n緊張してきちゃった…！！", 106001, "キャル", 80003, 7, 0, "", 38, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (200, 0, "主さま、わたくし\nペコリーヌさまとキャルさまと共に\n2.5周年を祝う生放送に\n出演する大役を仰せつかりました", 105901, "コッコロ", 80003, 8, 0, "", 20, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (201, 0, "多くの方々に\n『プリンセスコネクト！\nRe:Dive』の魅力をお伝えする\n重要な役割でございます", 105901, "コッコロ", 80003, 8, 0, "", 21, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (202, 0, "わたくし、全身全霊をもって\n生放送に取り組みたいと\n思っております", 105901, "コッコロ", 80003, 8, 0, "", 22, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (203, 0, "ですが、もしかしたら\nセリフを噛んでしまったり\n段取りを間違えてしまったり\nするかもしれません…", 105901, "コッコロ", 80003, 8, 0, "", 23, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (204, 0, "そのようなことがないよう\n練習はしっかりしておかなくては\nまずはこちらから…", 105901, "コッコロ", 80003, 8, 0, "", 24, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (205, 0, "オイッスー☆", 105901, "コッコロ", 80003, 8, 0, "", 25, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (206, 0, "先ほどキャルさまが練習されて\nいるのをお見かけしたので\nわたくしもと思いまして…\nいかがでしょうか？", 105901, "コッコロ", 80003, 8, 0, "", 26, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (207, 0, "良い感じ、ですか？\n…ふふ、ありがとうございます\n主さまのあたたかいお言葉があれば\nわたくしは百人力でございます", 105901, "コッコロ", 80003, 8, 0, "", 27, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (208, 0, "この大役を無事に成し遂げ\n主さまに素敵な2.5周年を\n迎えていただけるよう…\nわたくし、尽力いたしますね", 105901, "コッコロ", 80003, 8, 0, "", 28, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (209, 0, "オイッスー☆", 105801, "ペコリーヌ", 80003, 9, 0, "", 20, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (210, 0, "…う～ん、今のはちょっと\n違う感じがしますね\n堅苦しかったかもしれません", 105801, "ペコリーヌ", 80003, 9, 0, "", 21, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (211, 0, "あと６日で2.5周年ですか…", 105801, "ペコリーヌ", 80003, 9, 0, "", 22, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (212, 0, "この年月がオイッスーの\n歴史なんだと思うと\nじ～んとしちゃいます！\nやばいですね☆", 105801, "ペコリーヌ", 80003, 9, 0, "", 23, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (213, 0, "生放送で最高のオイッスー☆　を\nみなさんにお届けするために\n頑張らないと！\nそれじゃあもう一度…", 105801, "ペコリーヌ", 80003, 9, 0, "", 24, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (214, 0, "オイッスー☆", 105801, "ペコリーヌ", 80003, 9, 0, "", 25, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (215, 0, "…うう～ん、どうしてでしょう\nまだ何かが違う気がします…\nもしかしたら\nおなかが空きすぎてるとか？", 105801, "ペコリーヌ", 80003, 9, 0, "", 26, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (216, 0, "今さっき食べたばっかりですけど\nおなかが減っては\n良いオイッスー☆　は\n出せませんよね！", 105801, "ペコリーヌ", 80003, 9, 0, "", 27, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (217, 0, "そうと決まれば、コッコロちゃんと\nキャルちゃんを誘って\nごはんにしましょう！\n善は急げです！", 105801, "ペコリーヌ", 80003, 9, 0, "", 28, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (218, 0, "あ、二人が丁度いいところに！\nオイッス～☆　…ああ！！\n今の、今のですよ～♪", 105801, "ペコリーヌ", 80003, 9, 0, "", 29, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (219, 0, "なるほど、どんな時も\n自然体が一番ってことですね！\nこの調子で、生放送も\n頑張っちゃいます♪", 105801, "ペコリーヌ", 80003, 9, 0, "", 30, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (220, 0, "2.5周年まで残り５日ですが\nその前にもうすぐ生放送ですよ！\nコッコロちゃん\n準備の方はどうですか？", 105801, "ペコリーヌ", 80003, 10, 0, "", 31, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (221, 0, "はい。わたくし、しっかりと\n備えてまいりました\n万事抜かりはございません", 105901, "コッコロ", 80003, 10, 0, "", 29, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (222, 0, "おお～すごい自信を感じます…！\nいい生放送になりそうですね☆\n……あれ？　なんだかこの辺り\n揺れていませんか？", 105801, "ペコリーヌ", 80003, 10, 0, "", 32, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (223, 0, "…………", 106001, "キャル", 80003, 10, 0, "", 39, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (224, 0, "キャルさま？\nお風邪をひかれたんでしょうか\nひどい震えですが…", 105901, "コッコロ", 80003, 10, 0, "", 30, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (225, 0, "かかかか風邪じゃないわよ！\nここここれはただ\nななな生放送が楽しみ過ぎて\nワワワワクワクが止まらないだけ！", 106001, "キャル", 80003, 10, 0, "", 40, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (226, 0, "大丈夫ですかキャルちゃん！？\nそうだ、これを飲んでください！", 105801, "ペコリーヌ", 80003, 10, 0, "", 33, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (227, 0, "きき気がきくじゃない、ありがとっ\nごくっ、んく…ぶはぁっ！？\nちょっと何飲ませたの！？\n辛っ！　苦ぁ！？　甘ぁっ！？", 106001, "キャル", 80003, 10, 0, "", 41, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (228, 0, "これは魔物のエキスに薬草に\nその他色んなものを混ぜた\n特製の栄養ドリンクです！", 105801, "ペコリーヌ", 80003, 10, 0, "", 34, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (229, 0, "これを飲めば体ぽかぽかで\n元気いっぱいですよ♪", 105801, "ペコリーヌ", 80003, 10, 0, "", 35, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (230, 0, "このアホリーヌ！\n風邪じゃないって言ったでしょ！？\nどさくさに紛れて\nそんな恐ろしいもん飲ませんな～！", 106001, "キャル", 80003, 10, 0, "", 42, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (231, 0, "キャルさま\n震えが収まっておりますね\nよかったです…\nわたくし、心配いたしました", 105901, "コッコロ", 80003, 10, 0, "", 31, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (232, 0, "え？　ああ、ホントね…って\nだから風邪じゃないって\n言ってるのに…\nまあいいわこの際なんでも", 106001, "キャル", 80003, 10, 0, "", 43, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (233, 0, "えっへへ～♪　いつも通りの\nキャルちゃんに戻りましたし\n素敵な生放送が出来そうですね！\n今から楽しみです☆", 105801, "ペコリーヌ", 80003, 10, 0, "", 36, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (234, 0, "ランドソルのみなさま、こんにちは\n生放送の会場設営を担当しています\n【ギルド管理協会】のカリンです", 190801, "カリン", 80003, 11, 0, "", 6, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (235, 0, "【美食殿】のみなさんは\nまもなく始まる生放送に向けて\n最後の調整のため\n席を外しています", 190801, "カリン", 80003, 11, 0, "", 7, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (236, 0, "頑張っている３人の\n邪魔をするわけには\nいきませんので、ご容赦ください", 190801, "カリン", 80003, 11, 0, "", 8, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (237, 0, "ですので、本日は私から\n【美食殿】のみなさんの様子を\nお伝えさせていただこうと思います", 190801, "カリン", 80003, 11, 0, "", 9, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (238, 0, "まずはペコリーヌさんですが…\n何やら大量のおにぎりを\n食べているようです\nえっと…栄養は大事ですよね", 190801, "カリン", 80003, 11, 0, "", 10, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (239, 0, "次にコッコロさんですが\nこちらは発声練習をしています", 190801, "カリン", 80003, 11, 0, "", 11, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (240, 0, "一生懸命、小さなお口を開けて\n声を出す姿が応援したくなりますね", 190801, "カリン", 80003, 11, 0, "", 12, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (241, 0, "そしてキャルさんは…\nこれは…堂々としたものですね\n何もせず、ただ立ち尽くして…", 190801, "カリン", 80003, 11, 0, "", 13, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (242, 0, "あれ？\nもしかして緊張で気を失って…？", 190801, "カリン", 80003, 11, 0, "", 14, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (243, 0, "…ええと\n【美食殿】のみなさんは\nやる気十分なようですね！", 190801, "カリン", 80003, 11, 0, "", 15, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (244, 0, "３人とも生放送を\nいいものにしようと\n全力で頑張ってくれていますので\nどうかご期待ください", 190801, "カリン", 80003, 11, 0, "", 16, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (245, 0, "それでは\nまた明日お会いしましょう♪", 190801, "カリン", 80003, 11, 0, "", 17, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (246, 0, "2.5周年まであと３日！\nそして生放送は明日！\nなんかいよいよって感じね…", 106001, "キャル", 80003, 12, 0, "", 44, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (247, 0, "３人でい～っぱい練習しましたし\nきっと大丈夫ですよ☆", 105801, "ペコリーヌ", 80003, 12, 0, "", 37, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (248, 0, "ペコリーヌさまに\n大丈夫と言ってもらえると\nとても心強いですね", 105901, "コッコロ", 80003, 12, 0, "", 32, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (249, 0, "信じすぎちゃだめよコロ助\nこいつはなーんにも\n考えてないだけなんだから", 106001, "キャル", 80003, 12, 0, "", 45, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (250, 0, "ひどいですよぉキャルちゃ～ん！", 105801, "ペコリーヌ", 80003, 12, 0, "", 38, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (251, 0, "ふふ。お二人とも\n普段通りの様子で\n安心いたしました", 105901, "コッコロ", 80003, 12, 0, "", 33, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (252, 0, "はいっ☆\n生放送でもなんでも\n全力全開、わたしらしく\nぶつかっていくだけです！", 105801, "ペコリーヌ", 80003, 12, 0, "", 39, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (253, 0, "そうね。おめでたいことなんだし\nここまで来たんなら\n楽しめるだけ\n楽しむしかないわよね！", 106001, "キャル", 80003, 12, 0, "", 46, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (254, 0, "わたくしも、普段よりも心が\n熱くなっております\nこの胸の気持ちをお伝えできるよう\n精一杯努力いたします…！", 105901, "コッコロ", 80003, 12, 0, "", 34, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (255, 0, "それでは、いきましょう！\n明日の生放送、絶対に\n成功させましょうね☆", 105801, "ペコリーヌ", 80003, 12, 0, "", 40, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (256, 0, "えっと、最初のひと言は…あれ？\nキャルちゃん、わたし\n何て言うんでしたっけ？", 105801, "ペコリーヌ", 80003, 13, 0, "", 41, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (257, 0, "は！？\nなにいきなりど忘れしてるの！？\nっていうかあんた、台本は！？", 106001, "キャル", 80003, 13, 0, "", 47, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (258, 0, "忘れてきちゃいました☆", 105801, "ペコリーヌ", 80003, 13, 0, "", 42, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (259, 0, "忘れてきちゃいました☆\nで済ませられると思ってんの！？\nほら、あたし二冊持ってきたから\nこれ使いなさい！", 106001, "キャル", 80003, 13, 0, "", 48, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (260, 0, "マイクとは、こんな高い位置に\nあるものなのですね…！\n背伸びをすれば、何とか…\nう～ん、うぅ～ん…！", 105901, "コッコロ", 80003, 13, 0, "", 35, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (261, 0, "あぁもう\n少し下げればいいでしょ！？\nこれくらいでいい？\nまったく、世話が焼けるわね…", 106001, "キャル", 80003, 13, 0, "", 49, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (262, 0, "あれ？\nキャルちゃん、後ろ髪が\nはねちゃってますよ？", 105801, "ペコリーヌ", 80003, 13, 0, "", 43, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (263, 0, "え？　うそっ！？\nちゃんと確かめてきたのに！\nどこどこ！？", 106001, "キャル", 80003, 13, 0, "", 50, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (264, 0, "キャルさま、動かないで\nくださいまし。今くしで…\nはい、直りましたよ", 105901, "コッコロ", 80003, 13, 0, "", 36, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (265, 0, "あ、ありがと…はぁ。生放送\n本番までもうすぐなのに\nこんなことしてる場合じゃ\nないわよね", 106001, "キャル", 80003, 13, 0, "", 51, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (266, 0, "はい、時間は残りわずかです\nですが、慌ただしく\n動き回るこの時間も\nなんだか楽しくて…♪", 105901, "コッコロ", 80003, 13, 0, "", 37, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (267, 0, "コロ助、あんた…って\nそうじゃなくて！\n胸にジンワリきてる\n暇なんかないでしょ…！？", 106001, "キャル", 80003, 13, 0, "", 52, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (268, 0, "あはは♪\nキャルちゃんの動きが\nとっても面白いです♪\nやばいですね☆", 105801, "ペコリーヌ", 80003, 13, 0, "", 44, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (269, 0, "ふふ\nきっと面白い生放送になると\nわたくし、確信しております", 105901, "コッコロ", 80003, 13, 0, "", 38, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (270, 0, "絶対絶対、間違いありません！\n見てくれるみなさんが\n笑顔になれる時間を\nお届けしましょう！", 105801, "ペコリーヌ", 80003, 13, 0, "", 45, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (271, 0, "そんなの当然でしょ！\n誰が見たって面白いって\n言ってもらえるように\nあれだけ準備したんだから！", 106001, "キャル", 80003, 13, 0, "", 53, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (272, 0, "それでは\n記念日直前生放送！\n楽しみにしててくださいね☆", 105801, "ペコリーヌ", 80003, 13, 0, "", 46, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (273, 0, "こんにちは\n【ギルド管理協会】のカリンです", 190801, "カリン", 80003, 14, 0, "", 18, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (274, 0, "昨日の生放送は\nいかがだったでしょうか？", 190801, "カリン", 80003, 14, 0, "", 19, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (275, 0, "たくさんの笑顔と喜びと\nそして驚きを受け取って\nいただけたのではないかと思います", 190801, "カリン", 80003, 14, 0, "", 20, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (276, 0, "そしていよいよ\n明日は2.5周年の当日\n待ちに待った記念日を\n迎えることとなります", 190801, "カリン", 80003, 14, 0, "", 21, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (277, 0, "【美食殿】のみなさんも\n張り切って様々な準備を\nされていますよ", 190801, "カリン", 80003, 14, 0, "", 22, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (278, 0, "【ギルド管理協会】も\n万全のサポート体制で\n協力してまいりたいと思います", 190801, "カリン", 80003, 14, 0, "", 23, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (279, 0, "…ふふ、本当に楽しみですね\n【ギルド管理協会】の職員として\nだけではなく、私個人としても…", 190801, "カリン", 80003, 14, 0, "", 24, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (280, 0, "この記念日を迎えられることが\n心から楽しみですし\n幸せを感じています", 190801, "カリン", 80003, 14, 0, "", 25, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (281, 0, "きっと【美食殿】のみなさんは\nそれ以上に心を弾ませて\nいることでしょう", 190801, "カリン", 80003, 14, 0, "", 26, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (282, 0, "それでは\n明日からの2.5周年を\nどうぞ、お楽しみに…♪", 190801, "カリン", 80003, 14, 0, "", 27, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (283, 0, "準備はいいですかっ？\n…いっきますよー！", 105801, "ペコリーヌ", 80003, 15, 0, "", 47, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (284, 0, "祝！", 106001, "キャル", 80003, 15, 0, "", 54, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (285, 0, "2.5周年！", 105901, "コッコロ", 80003, 15, 0, "", 39, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (286, 0, "おめでとうございま～す☆", 105801, "ペコリーヌ", 80003, 15, 0, "", 48, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (287, 0, "少し前まではまだまだ先じゃない\nとか言ってたけど\n本当にあっという間だったわね", 106001, "キャル", 80003, 15, 0, "", 55, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (288, 0, "光陰矢の如し…\nとはこのことでございますね\nでも、今日という日を無事に\n迎えることができて良かったです", 105901, "コッコロ", 80003, 15, 0, "", 40, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (289, 0, "コッコロちゃん！　キャルちゃん！\n落ち着くには\nまだ早いですよ！\n盛り上がるのはこれからです☆", 105801, "ペコリーヌ", 80003, 15, 0, "", 49, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (290, 0, "ほんとあんたはいつも\n全力全開ねー\nでもそうね、記念日なんだし\nパーっといきましょ！", 106001, "キャル", 80003, 15, 0, "", 56, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (291, 0, "ええ、わたくしも全力全開で\nまいります…！\n主さま、さあ\nどうぞ手を取ってくださいまし…♪", 105901, "コッコロ", 80003, 15, 0, "", 41, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (292, 0, "あんたもコロ助も、浮かれて\n転ぶんじゃないわよ？\n…仕方ないから、あたしも\n手を繋いであげるわよ", 106001, "キャル", 80003, 15, 0, "", 57, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (293, 0, "あー！　二人ともずるいです！\nわたしもっ、ギュー♪", 105801, "ペコリーヌ", 80003, 15, 0, "", 50, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (294, 0, "ちょっ、ペコリーヌ！\nくっつき過ぎよ！", 106001, "キャル", 80003, 15, 0, "", 58, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (295, 0, "記念日だから\n平気平気♪\nやばいですね☆", 105801, "ペコリーヌ", 80003, 15, 0, "", 51, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (296, 0, "意味分かんないわよ！", 106001, "キャル", 80003, 15, 0, "", 59, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (297, 0, "ふふ。このめでたき日に\n喜びがあふれておりますね\n主さまは…いかがでしょうか？", 105901, "コッコロ", 80003, 15, 0, "", 42, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (298, 0, "喜んでいただけているならば\nわたくしはとてもとても\n幸せでございます", 105901, "コッコロ", 80003, 15, 0, "", 43, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (299, 0, "さぁ、2.5周年を\n楽しみ尽くしますよ☆\nまだまだ食べたいものもありますし\nやりたいこともたくさんです！", 105801, "ペコリーヌ", 80003, 15, 0, "", 52, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (300, 0, "分かった、分かったから\n引っ張るんじゃないわよ！\n…そんな掴まなくても\nちゃんとついていくから", 106001, "キャル", 80003, 15, 0, "", 60, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (301, 0, "ペコリーヌさま…キャルさま…\n主さま…共にまいりましょう\nどこまでも…！", 105901, "コッコロ", 80003, 15, 0, "", 44, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (302, 0, "はい！　それでは2.5周年\n食べつくしツアーへ！\nそして、その先の未来へ\n向かって出発しましょう！", 105801, "ペコリーヌ", 80003, 15, 0, "", 53, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (303, 0, "2.5周年\nありがとうございます！", 105801, "ペコリーヌ・コッコロ・キャル", 80003, 15, 1, "105901,45,106001,61", 54, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (304, 1, "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 190804, "カリン", 60002, 0, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (305, 1, "今日の運勢は姫吉！　どんな不可能も可能にできちゃう！　　　　仲間と食卓を囲めばさらに運気上昇よ！　ただし魔物料理以外！", 0, "", 60002, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (306, 1, "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 0, "", 60002, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (307, 1, "今日の運勢は姫吉！　最強の運勢でどんなドジも跳ね除けます！　大切な人と一緒に、最高の一日になること間違いなし！", 0, "", 60002, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (308, 1, "今日の運勢は姫吉！　どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！　新しい一歩を踏み出そう！", 0, "", 60002, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (309, 2, "今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", 0, "", 60002, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (310, 1, "今日の運勢は大吉！　お裁縫好きな女の子のお墨付きです！　　　お世話したがりの妹にめいっぱい愛されちゃうかも！？", 0, "", 60002, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (311, 1, "今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", 0, "", 60002, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (312, 1, "今日の運勢は大吉！　ラッキーワードは「ちぇる～ん♪」　　　　出会う人みんなに言ってあげると、ハッピーになれますよ！", 0, "", 60002, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (313, 1, "今日の運勢は大吉！　運勢はバッチリで無敵状態！　　　　　　　龍眼で全てを見通して、思い通りの一日を過ごしましょう！", 0, "", 60002, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (314, 2, "今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", 0, "", 60002, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (315, 1, "今日の運勢は中吉！　家の中でゆっくり過ごすのがよさそう！　　ラッキーアイテムはゲームよ！　ベストスコアを更新できるかも？", 0, "", 60002, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (316, 1, "今日の運勢は中吉！　上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？", 0, "", 60002, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (317, 1, "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 0, "", 60002, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (318, 1, "今日の運勢は中吉！　日頃の努力が報われます！　　　　　　　　親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。", 0, "", 60002, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (319, 1, "今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたい焼き！　和菓子パワーで売上アップです！", 0, "", 60002, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (320, 1, "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 0, "", 60002, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (321, 2, "今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかのごとく、色々な事がうまくいきますよ♪", 0, "", 60002, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (322, 1, "今日の運勢は小吉！　まだ見ぬ危険が隠れているかも！　　　　　でも安心しろ！　提督が貴公を守ってくれるはずだぞ！", 0, "", 60002, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (323, 1, "今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", 0, "", 60002, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (324, 1, "今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", 0, "", 60002, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (325, 1, "今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", 0, "", 60002, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (326, 1, "今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", 0, "", 60002, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (327, 1, "今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", 0, "", 60002, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (328, 2, "今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", 0, "", 60002, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (329, 0, "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 190804, "カリン", 60002, 0, 0, "", 2, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (330, 0, "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 190804, "カリン", 60002, 7, 0, "", 3, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (331, 0, "ささ、シェフィさまはこちらへ…", 105901, "コッコロ", 80005, 1, 0, "", 1, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (332, 0, "コッコロさん、どこへ行くの…？\n…え？", 106401, "シェフィ", 80005, 1, 0, "", 1, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (333, 0, "『おめでとうございます！\nわ～パチパチー！』\n…という感じでどうですかね！？", 105801, "ペコリーヌ", 80005, 1, 0, "", 1, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (334, 0, "ではわたくしも\n後ろからクラッカーを鳴らして\n応戦いたします\nああ、当日が待ち遠しいですね", 105901, "コッコロ", 80005, 1, 0, "", 2, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (335, 0, "ええと…\n二人とも何をしているの？", 106401, "シェフィ", 80005, 1, 0, "", 2, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (336, 0, "シェフィは初めてだもんね\nあの日が近いからって\n予行練習してんのよ\n気が早いわよね～", 106001, "キャル", 80005, 1, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (337, 0, "あの日…？", 106401, "シェフィ", 80005, 1, 0, "", 3, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (338, 0, "その通りです…\nいよいよ記念すべきあの日が\n近づいてきましたよ！", 105801, "ペコリーヌ", 80005, 1, 0, "", 2, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (339, 0, "『プリンセスコネクト！\nRe:Dive』3.5周年！", 105801, "ペコリーヌ", 80005, 1, 0, "", 3, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (340, 0, "やばいですね☆", 190801, "カリン", 80005, 1, 0, "", 1, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (341, 0, "って、なにしれっと\n参加してんのよカリン！", 106001, "キャル", 80005, 1, 0, "", 2, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (342, 0, "ふふ、いいじゃないですか\n【ギルド管理協会】として\n私もみなさんと一緒に\nお祝いをさせてください！", 190801, "カリン", 80005, 1, 0, "", 2, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (343, 0, "それに…記念日が近づけば\nとっておきの情報を\nお届けしますから♪", 190801, "カリン", 80005, 1, 0, "", 3, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (344, 0, "というわけで\n今日からシェフィちゃんも一緒に\nカウントダウンしちゃいましょう！\n3.5周年まで…", 105801, "ペコリーヌ", 80005, 1, 0, "", 4, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (345, 0, "えっ！？　ええとええと…！\nあ、あと14日…！", 106401, "シェフィ", 80005, 1, 0, "", 4, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (346, 0, "3.5周年まであと13日\n豪華に、そして盛大に\nお祝いしたいですね☆", 105801, "ペコリーヌ", 80005, 2, 0, "", 5, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (347, 0, "豪華といえば前にとある貴族さまが\n舞踏会を開かれたそうで\n主さまがそのお手伝いを\nしておりました", 105901, "コッコロ", 80005, 2, 0, "", 3, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (348, 0, "そこで美しい所作を学ばれたので\nわたくしも教えていただきました\nしゃなり、しゃなり…\nいかがでしょう？", 105901, "コッコロ", 80005, 2, 0, "", 4, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (349, 0, "すっごく上手ですよ☆\nまるでお姫様みたいです\nせっかくなのでわたしも\nしゃなりしゃなり", 105801, "ペコリーヌ", 80005, 2, 0, "", 6, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (350, 0, "さすがでございます\nペコリーヌさま", 105901, "コッコロ", 80005, 2, 0, "", 5, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (351, 0, "いや、あんたは\nできなきゃダメでしょ\n本物のお姫様なんだし", 106001, "キャル", 80005, 2, 0, "", 3, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (352, 0, "しゃなり、しゃなり…\nふふ、案外できるものね", 106401, "シェフィ", 80005, 2, 0, "", 5, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (353, 0, "わぁ！\nシェフィちゃん\n姿勢がとってもキレイです♪", 105801, "ペコリーヌ", 80005, 2, 0, "", 7, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (354, 0, "さ、次はキャルさまの\n番でございますよ", 105901, "コッコロ", 80005, 2, 0, "", 6, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (355, 0, "あ、あたしはいいわよ！\nそういうの全然分かんないし…", 106001, "キャル", 80005, 2, 0, "", 4, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (356, 0, "大丈夫\nやってみると結構楽しいわよ\nほらほらっ", 106401, "シェフィ", 80005, 2, 0, "", 6, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (357, 0, "そ、そこまで言うなら…\nしゃなにゅわきゃあっ！", 106001, "キャル", 80005, 2, 0, "", 5, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (358, 0, "いたたた…もぉお～！\nなんであたしがこんな目に～！", 106001, "キャル", 80005, 2, 0, "", 6, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (359, 0, "まぁまぁ\n記念日までに練習すれば\nできるようになるかもしれません\nよろしければお教えいたしますよ", 105901, "コッコロ", 80005, 2, 0, "", 7, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (360, 0, "よし！\nあんたたちができて\nあたしだけできないのはしゃくだし\nやってやろうじゃないの！！", 106001, "キャル", 80005, 2, 0, "", 7, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (361, 0, "3.5周年まであと12日\n記念日当日はもちろんですが\nその日を待つ時間というのも\n心躍ります", 105901, "コッコロ", 80005, 3, 0, "", 8, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (362, 0, "分かりますっ！\nどんな特別な料理を食べられるのか\n考えるだけでワクワクしますよね！", 105801, "ペコリーヌ", 80005, 3, 0, "", 8, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (363, 0, "特別な料理といえば、お祭りですね\nそういえば主さまは学生として\n聖学祭に参加されたこと\nがあるとか…", 105901, "コッコロ", 80005, 3, 0, "", 9, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (364, 0, "聖学祭…って、なにかしら？", 106401, "シェフィ", 80005, 3, 0, "", 7, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (365, 0, "聖テレサ女学院の祭典ですよ\n二つのチームが競い合い\n青春を満喫するのが趣旨のようです", 105901, "コッコロ", 80005, 3, 0, "", 10, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (366, 0, "それってカルミナの\nサプライズライブがあった\nお祭りよね？\nちょっと見たかったかも…", 106001, "キャル", 80005, 3, 0, "", 8, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (367, 0, "カルミナの後の\nライブも好評だったらしいじゃない\n確か、なかよし部\nだったっけ…？", 106001, "キャル", 80005, 3, 0, "", 9, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (368, 0, "なかよし部…\n仲が良さそうな名前で\nやばいですね☆", 105801, "ペコリーヌ", 80005, 3, 0, "", 9, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (369, 0, "いや、そのまんますぎでしょ…", 106001, "キャル", 80005, 3, 0, "", 10, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (370, 0, "聖学祭かぁ…なんだか楽しそうね\nそれになかよし部の人たちも\n気になるわ", 106401, "シェフィ", 80005, 3, 0, "", 8, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (371, 0, "それじゃあわたしたちも、\n負けじと仲良くしましょう♪\nほらほらシェフィちゃん、\nぎゅーっ☆　ですよ♪", 105801, "ペコリーヌ", 80005, 3, 0, "", 10, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (372, 0, "えっ？　ええ…\nぎゅーっ…？", 106401, "シェフィ", 80005, 3, 0, "", 9, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (373, 0, "3.5周年まであと11日！？\nお祝いの準備進んでないんだけど…\nああ～昨日に戻りたいわ…", 106001, "キャル", 80005, 4, 0, "", 11, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (374, 0, "そういえばそんな魔道具があるって\n聞いたことがあるわね\n確か、名前はタイムラーベ…", 106401, "シェフィ", 80005, 4, 0, "", 10, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (375, 0, "なにそれヤバいわね\nでも本当にあるんだったら\n準備よりももっとやり直したいこと\nたくさんあるんだけど…", 106001, "キャル", 80005, 4, 0, "", 12, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (376, 0, "もしや正月の件でしょうか…？\nあの時はお金がなくて\n苦労しましたから", 105901, "コッコロ", 80005, 4, 0, "", 11, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (377, 0, "あれはそうね…\nお金を湯水のように使う\nぺコリーヌを止められたら\nあんな苦労をすることもなかったし", 106001, "キャル", 80005, 4, 0, "", 13, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (378, 0, "そんなこともありましたね！\nやり直したいといえば\n『きゃるきゃる～ん♪』\nの方かと思いましたよ！", 105801, "ペコリーヌ", 80005, 4, 0, "", 11, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (379, 0, "バラすんじゃないわよ\nこのアホリーヌ！\nシェフィはそれ\n知らないんだから！", 106001, "キャル", 80005, 4, 0, "", 14, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (380, 0, "こうなったらもう、なんとか\nタイムラーべを探し出して\n今の会話をなかったことに…\nって、どうしたのよシェフィ", 106001, "キャル", 80005, 4, 0, "", 15, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (381, 0, "うん…もし、私だったら…\n私が知らないみんなとの時間を\n見てみたいな、って…", 106401, "シェフィ", 80005, 4, 0, "", 11, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (382, 0, "シェフィちゃん！　タイムなんとか\nなんかなくても大丈夫ですよ！\n一緒の時間はこれから\nどんどん作ればいいんですから！", 105801, "ペコリーヌ", 80005, 4, 0, "", 12, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (383, 0, "はい、今この瞬間も\n未来にはかけがえのない思い出に\nなっていることでしょう", 105901, "コッコロ", 80005, 4, 0, "", 12, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (384, 0, "だからそんな顔しないの\nほら、お祝いの準備、進めるわよ！", 106001, "キャル", 80005, 4, 0, "", 16, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (385, 0, "みんな…そうね\n最高のお祝いにして\n最高の思い出にしましょう！", 106401, "シェフィ", 80005, 4, 0, "", 12, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (386, 0, "3.5周年まで、あと10日！\nもうすぐですよー！\n楽しみすぎて、やばいですね！", 105801, "ペコリーヌ", 80005, 5, 0, "", 13, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (387, 0, "そういえば…たくさんのおもちゃが\n子どもたちを襲うっていう\n騒動もありましたね…\nなんでも勝手に動き出したとか！", 105801, "ペコリーヌ", 80005, 5, 0, "", 14, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (388, 0, "学校や孤児院とかに\nちっちゃなおもちゃが乗り込んで\n暴れたみたいですよ！", 105801, "ペコリーヌ", 80005, 5, 0, "", 15, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (389, 0, "暴れたって言っても\n所詮はおもちゃじゃない\nどうせちっさいんでしょ？", 106001, "キャル", 80005, 5, 0, "", 17, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (390, 0, "だったら魔法で\n全部ぶっ飛ばせばいいじゃない！\n大したことないわよ！", 106001, "キャル", 80005, 5, 0, "", 18, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (391, 0, "キャルってば…\n相手は子どもが\n大事にしてる物なのよ…？", 106401, "シェフィ", 80005, 5, 0, "", 13, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (392, 0, "乱暴な発言は\nめっ、でございますよ？\n子どもの教育に悪影響を\n与えてしまいますから…", 105901, "コッコロ", 80005, 5, 0, "", 13, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (393, 0, "キャルちゃんだって\n意外と猫グッズとか\nたっくさん集めてますよね？\nもしその子たちが暴れたら…？", 105801, "ペコリーヌ", 80005, 5, 0, "", 16, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (394, 0, "う、うっさいわね！\n意外とか言うな！\n…ま、まあ確かに正面切って\n魔法でぶっ飛ばせないかもね…", 106001, "キャル", 80005, 5, 0, "", 19, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (395, 0, "あはは☆\nキャルちゃんのそういうところ\n好きですよ♪", 105801, "ペコリーヌ", 80005, 5, 0, "", 17, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (396, 0, "そんなキャルちゃんに猫グッズを\nプレゼントしちゃいますね！\n一部で流行っていた、たい焼き屋の\nおまけフィギュアですよ♪", 105801, "ペコリーヌ", 80005, 5, 0, "", 18, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (397, 0, "乱暴に扱ったりしないでくださいね\nひとりでに暴れ出しちゃうかも\nしれませんから！", 105801, "ペコリーヌ", 80005, 5, 0, "", 19, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (398, 0, "3.5周年まであと９日\nここでみなさんに\nビックニュースですよ！", 190801, "カリン", 80005, 6, 0, "", 4, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (399, 0, "3.5周年を祝う生放送に\n去年と同様【美食殿】の\nみなさんにご出演いただくことが\n決定しましたー！", 190801, "カリン", 80005, 6, 0, "", 5, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (400, 0, "…えっ！？", 106001, "キャル", 80005, 6, 0, "", 20, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (401, 0, "本当ですか！？\nそれじゃ今から張り切って\n生放送中に食べる魔物料理を\n作らなくちゃですね☆", 105801, "ペコリーヌ", 80005, 6, 0, "", 20, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (402, 0, "いや…がんばるところは\nそこじゃないような…\nというか去年も出演してたのね\nすごいじゃない！", 106401, "シェフィ", 80005, 6, 0, "", 14, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (403, 0, "はい。とても緊張しますが\nやりがいのある大役です\n一緒にがんばりましょうね\nシェフィさま", 105901, "コッコロ", 80005, 6, 0, "", 14, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (404, 0, "わ、私も出るの！？　でも…\n私も【美食殿】の一人だものね\nそれなら今からしっかり準備をして\nコンディションを整えないと…", 106401, "シェフィ", 80005, 6, 0, "", 15, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (405, 0, "ふふん♪\n生放送直前のカチコチになった\nシェフィの姿が楽しみだわ！", 106001, "キャル", 80005, 6, 0, "", 21, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (406, 0, "去年のキャルちゃんは\n緊張しすぎてずっと震えて\nかわいかったですもんね！\n今年もあの姿が見たいです！", 105801, "ペコリーヌ", 80005, 6, 0, "", 21, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (407, 0, "ぶっ殺すぞ！？", 106001, "キャル", 80005, 6, 0, "", 22, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (408, 0, "というわけで\n『プリンセスコネクト！\nRe:Dive』の魅力を\nお伝えする生放送をお楽しみに♪", 190801, "カリン", 80005, 6, 0, "", 6, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (409, 0, "3.5周年まであと８日\nでございますよ\n楽しみですね、主さま", 105901, "コッコロ", 80005, 7, 0, "", 15, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (410, 0, "そういえばあんた\n夏休みの宿題は\nきちんとやってるの？", 106001, "キャル", 80005, 7, 0, "", 23, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (411, 0, "宿題…学校に通うのも\n楽しいことばかりじゃ\nないのね", 106401, "シェフィ", 80005, 7, 0, "", 16, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (412, 0, "あれ？　そういえば\n少し前にルーセント学院で\n何かあったような…", 105801, "ペコリーヌ", 80005, 7, 0, "", 22, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (413, 0, "ああ、始業式の日に\n大捕り物があったって\n話題になってたわね", 106001, "キャル", 80005, 7, 0, "", 24, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (414, 0, "夏休みを終わらせないって\n騒いでたっていう話？\nあれ本当なの？\n都市伝説だと思ってたわ", 106401, "シェフィ", 80005, 7, 0, "", 17, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (415, 0, "その一件ならよく存じ上げて\nおります。ですから主さま\n次の機会にはわたくしと一緒に\nがんばりましょう", 105901, "コッコロ", 80005, 7, 0, "", 16, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (416, 0, "楽しそう…私も一緒にやりたいな\nママ…じゃ、じゃなくて！\nコッコロさん、私もまざっていい？", 106401, "シェフィ", 80005, 7, 0, "", 18, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (417, 0, "もちろんでございます\n仲良くお勉強いたしましょう", 105901, "コッコロ", 80005, 7, 0, "", 17, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (418, 0, "しれっと教育ママが\n生まれてる…？", 106001, "キャル", 80005, 7, 0, "", 25, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (419, 0, "お勉強は大切ですよ！\nキャルちゃんも一緒に\nがんばりましょう！", 105801, "ペコリーヌ", 80005, 7, 0, "", 23, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (420, 0, "え～～～～！？", 106001, "キャル", 80005, 7, 0, "", 26, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (421, 0, "3.5周年まであと７日〜♪\nふふ～ん♪\nふんふふ～ん♪", 106001, "キャル", 80005, 8, 0, "", 27, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (422, 0, "…\nねぇコッコロさん\nキャル、どうしちゃったの？", 106401, "シェフィ", 80005, 8, 0, "", 19, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (423, 0, "とてもご機嫌そうに\n鼻歌を歌ってらっしゃいますね\n耳も尻尾もリズミカルに\n揺れて…ノリノリでございます", 105901, "コッコロ", 80005, 8, 0, "", 18, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (424, 0, "あれはですね！\nカルミナのみなさんの\nサマーライブのチケットが\n手に入ったからなんですよ♪", 105801, "ペコリーヌ", 80005, 8, 0, "", 24, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (425, 0, "ええっ！？\nあのライブのチケットって確か\n入手困難だったんじゃ…", 106401, "シェフィ", 80005, 8, 0, "", 20, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (426, 0, "ふふふふ～ん♪\nしゃいにんぐふゅ～ちゃ～♪", 106001, "キャル", 80005, 8, 0, "", 28, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (427, 0, "なるほど…\nキャルさまがあのように\nなってしまうのも頷けますね", 105901, "コッコロ", 80005, 8, 0, "", 19, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (428, 0, "…カルミナの\n『Shining Future』\nの中に、シャイニングフューチャー\nって歌詞はなかったはずだけど…", 106401, "シェフィ", 80005, 8, 0, "", 21, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (429, 0, "ふんふ…はっ！？\nあっ、あんたたち！\nなに人の鼻歌を\n勝手に聞いてるのよ！？", 106001, "キャル", 80005, 8, 0, "", 29, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (430, 0, "こっ、これは別に\nカルミナの曲じゃなくて…\nあたしのオリジナルソングよ！\n聞いたらお金取るわよっ！？", 106001, "キャル", 80005, 8, 0, "", 30, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (431, 0, "えへへ、キャルちゃん\nカルミナのサマーライブ\n思いっきり楽しみましょうね☆", 105801, "ペコリーヌ", 80005, 8, 0, "", 25, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (432, 0, "も～っ！\n生暖かい目で見るな～～！\nぶっ殺すわよ～～～！", 106001, "キャル", 80005, 8, 0, "", 31, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (433, 0, "3.5周年まであと６日\n３人も言ってたけど\nあっという間だったわね", 106401, "シェフィ", 80005, 9, 0, "", 22, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (434, 0, "…えっ？\n生放送の意気込み！？\n突然なに！？", 106401, "シェフィ", 80005, 9, 0, "", 23, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (435, 0, "ええと…\nとにかく失敗しないように\n台本たくさん読んで…\nそれから…", 106401, "シェフィ", 80005, 9, 0, "", 24, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (436, 0, "えっ！？\nトラブルがあったら\nどうするのかって！？\nそ、それは…！", 106401, "シェフィ", 80005, 9, 0, "", 25, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (437, 0, "とにかく落ち着いて\nスタッフさんの指示を聞いて…", 106401, "シェフィ", 80005, 9, 0, "", 26, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (438, 0, "それから、それから…！\nぅ、ぅぅっ…！", 106401, "シェフィ", 80005, 9, 0, "", 27, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (439, 0, "―びえぇぇ～んっ！！！", 106401, "シェフィ", 80005, 9, 0, "", 28, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (440, 0, "どうされましたか、シェフィさま", 105901, "コッコロ", 80005, 9, 0, "", 20, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (441, 0, "ううっ…ひっく…\nママッ…！", 106401, "シェフィ", 80005, 9, 0, "", 29, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (442, 0, "よしよし、緊張されてるのですね\nママが傍におりますよ\n主さま、少々お待ちくださいませ", 105901, "コッコロ", 80005, 9, 0, "", 21, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (443, 0, "…ふぅ\nシェフィさま\n生放送への意気込み\nお話しできそうですか？", 105901, "コッコロ", 80005, 9, 0, "", 22, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (444, 0, "…ううっ\n恥ずかしすぎて\nもう生放送出られない…", 106401, "シェフィ", 80005, 9, 0, "", 30, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (445, 0, "主さま\n3.5周年まであと５日\nでございます", 105901, "コッコロ", 80005, 10, 0, "", 23, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (446, 0, "ですがその前に\n生放送がありますね", 105901, "コッコロ", 80005, 10, 0, "", 24, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (447, 0, "…生放送に向けた\n意気込みでございますか？", 105901, "コッコロ", 80005, 10, 0, "", 25, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (448, 0, "もちろんわたくしは\n主さまのために\n全身全霊を込めて\n楽しい時間をご提供いたします", 105901, "コッコロ", 80005, 10, 0, "", 26, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (449, 0, "…と、意気込んでみましたが\nうまくできるか少し不安です\n声が小さくなったり\n間違えてしまったらどうしようと…", 105901, "コッコロ", 80005, 10, 0, "", 27, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (450, 0, "ですがわたくしは\n一人ではありません\n【美食殿】のみなさまが\nおります", 105901, "コッコロ", 80005, 10, 0, "", 28, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (451, 0, "どんな困難も\nみなさまと一緒なら\n乗り越えられると\nわたくし、確信しております", 105901, "コッコロ", 80005, 10, 0, "", 29, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (452, 0, "それに今回はシェフィさまも\nご参加されるわけですし\nママとしてお手本に\nならねばなりませんね", 105901, "コッコロ", 80005, 10, 0, "", 30, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (453, 0, "主さま。3.5周年も\n食卓を囲んでいる時のような\n楽しい思い出を\n一緒に作りましょうね", 105901, "コッコロ", 80005, 10, 0, "", 31, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (454, 0, "3.5周年まであと４日！\nやばいですね☆", 105801, "ペコリーヌ", 80005, 11, 0, "", 26, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (455, 0, "はいはい、やばいわね\nというかもうすぐ生放送だけど\nあんた準備はできてるの？", 106001, "キャル", 80005, 11, 0, "", 32, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (456, 0, "ばっちりオイッスー☆　ですよ！\n『王家の装備』も全開です！", 105801, "ペコリーヌ", 80005, 11, 0, "", 27, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (457, 0, "あとは前回を超える\n最高のオイッスー☆　を\nお届けできるように\n練習あるのみですかね！", 105801, "ペコリーヌ", 80005, 11, 0, "", 28, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (458, 0, "キャルちゃんは\nどうなんですか？\nオイッスー☆　を\n毎日ちゃんと練習してますか？", 105801, "ペコリーヌ", 80005, 11, 0, "", 29, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (459, 0, "はぁ！？　なんであたしまで\nその変なあいさつを練習しないと\nいけないのよ！", 106001, "キャル", 80005, 11, 0, "", 33, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (460, 0, "もしかしてやってないんですか？\nダメですよキャルちゃん！\nシェフィちゃんだってちゃんと\n毎日練習してるのに！", 105801, "ペコリーヌ", 80005, 11, 0, "", 30, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (461, 0, "こうなったらわたしがキャルちゃん\nにオイッスー☆　の『オ』から\nしっかり教えてあげないと！", 105801, "ペコリーヌ", 80005, 11, 0, "", 31, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (462, 0, "オイッスー☆　の『オ』は\n口を大きく開いて〜\nドラゴンの骨つき肉に\nかぶりつく直前をイメージして〜", 105801, "ペコリーヌ", 80005, 11, 0, "", 32, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (463, 0, "だからあたしはやるなんて一言も…", 106001, "キャル", 80005, 11, 0, "", 34, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (464, 0, "オイッスー☆", 105801, "ペコリーヌ", 80005, 11, 0, "", 33, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (465, 0, "聞きなさいっての！！", 106001, "キャル", 80005, 11, 0, "", 35, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (466, 0, "3.5周年まであと３日…\nそして生放送は、明日…", 106401, "シェフィ", 80005, 12, 0, "", 31, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (467, 0, "もっと台本を\n読み込んでおかないと…\nあと発声練習も…", 106401, "シェフィ", 80005, 12, 0, "", 32, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (468, 0, "おいっす！\n…こうじゃなかったわね\nええと確か…", 106401, "シェフィ", 80005, 12, 0, "", 33, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (469, 0, "うう…あんなに練習したのに\nこれじゃみんなに迷惑かけちゃう…", 106401, "シェフィ", 80005, 12, 0, "", 34, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (470, 0, "【美食殿】の一員として\n認められるように\n頑張らないといけないのに\nよし、もう一度…", 106401, "シェフィ", 80005, 12, 0, "", 35, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (471, 0, "やってますねシェフィちゃん！", 105801, "ペコリーヌ", 80005, 12, 0, "", 34, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (472, 0, "なによ、考えることは\nみんな同じってこと？", 106001, "キャル", 80005, 12, 0, "", 36, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (473, 0, "ふふ。シェフィさま\nよろしければ\n仲間に入れてください\n一緒にやればきっとうまくできます", 105901, "コッコロ", 80005, 12, 0, "", 32, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (474, 0, "みんな…もちろんよ！", 106401, "シェフィ", 80005, 12, 0, "", 36, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (475, 0, "それじゃ明日の生放送に向けて\n一緒に練習がんばりましょう☆", 105801, "ペコリーヌ", 80005, 12, 0, "", 35, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (476, 0, "3.5周年まであと２日と\n迫った本日は…\nいよいよ生放送です！", 190801, "カリン", 80005, 13, 0, "", 7, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (477, 0, "【美食殿】のみなさんが\n準備に入られていますので\nそれぞれ繋いでみましょう！\nまずはペコリーヌさんです！", 190801, "カリン", 80005, 13, 0, "", 8, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (478, 0, "今日もオイッスー☆\nみんなで一緒に\nオイッスー☆", 105801, "ペコリーヌ", 80005, 13, 0, "", 36, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (479, 0, "お手本になるような\n発声練習ですね！\nそれでは続いてコッコロさん", 190801, "カリン", 80005, 13, 0, "", 9, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (480, 0, "はじめちょろちょろ\nなかぱっぱ～♪\n生放送前にみなさまで\n食卓を囲んで英気を養いましょう", 105901, "コッコロ", 80005, 13, 0, "", 33, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (481, 0, "さすが【美食殿】のママですね！\nそしてキャルさんは…", 190801, "カリン", 80005, 13, 0, "", 10, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (482, 0, "大丈夫…大丈夫…\nあたしは大丈夫…", 106001, "キャル", 80005, 13, 0, "", 37, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (483, 0, "す、すごく震えてますけど\n大丈夫でしょうか…？\nそして今回初参加となる\n期待の新人シェフィさん！", 190801, "カリン", 80005, 13, 0, "", 11, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (484, 0, "あうー？", 106401, "シェフィ", 80005, 13, 0, "", 37, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (485, 0, "あ…", 105801, "みんな", 80005, 13, 1, "105901,34,106001,38,190801,12", 37, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (486, 0, "ちょ、ちょっとシェフィ！？\nなに赤ちゃん返りしてん―\nあ痛ぁっ！\n噛んだわこいつーっ！", 106001, "キャル", 80005, 13, 0, "", 39, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (487, 0, "シェフィさま\n緊張しすぎて\nしまったのでしょうね…\nおーよしよし…", 105901, "コッコロ", 80005, 13, 0, "", 35, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (488, 0, "シェフィちゃん！\nそういう時は手のひらに\n好きな文字を書いて\n食べちゃうといいですよ！", 105801, "ペコリーヌ", 80005, 13, 0, "", 38, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (489, 0, "…ええと、現場からは以上です！\n生放送はもうすぐ！\n特別なお知らせもありますので\nどうぞお楽しみに！", 190801, "カリン", 80005, 13, 0, "", 13, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (490, 0, "3.5周年の記念日も\nいよいよ明日ね\n…って、あれ？", 106401, "シェフィ", 80005, 14, 0, "", 38, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (491, 0, "記念日はこの森へ行きませんか！？\nすっごく美味しいお肉が\nとれるんです☆", 105801, "ペコリーヌ", 80005, 14, 0, "", 39, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (492, 0, "うげ、またあの魔物？\nさすがに今度は\n丸焼きとかはやめてよね…\n見た目がヤバすぎるし", 106001, "キャル", 80005, 14, 0, "", 40, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (493, 0, "ふふ、キャルさまもだいぶ\n魔物肉に慣れてきたようですね\n調理ならばわたくしに\nお任せください♪", 105901, "コッコロ", 80005, 14, 0, "", 36, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (494, 0, "みんな、何をしているの？\nなんだか、\n不穏な単語が聞こえたんだけど…", 106401, "シェフィ", 80005, 14, 0, "", 39, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (495, 0, "シェフィちゃん！\n明日の食べ尽くしツアーの\n相談をしてたんですよ！", 105801, "ペコリーヌ", 80005, 14, 0, "", 40, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (496, 0, "はい。明日は【美食殿】の\n一員となったシェフィさまと一緒に\n初めて記念日を過ごすのですから\n特別なコース料理を用意しませんと", 105901, "コッコロ", 80005, 14, 0, "", 37, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (497, 0, "ふふん♪\n猫の毛も逆立つような\nあれこれを食べさせられるから\n覚悟しておいたほうがいいわよ？", 106001, "キャル", 80005, 14, 0, "", 41, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (498, 0, "へ、へぇ…", 106401, "シェフィ", 80005, 14, 0, "", 40, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (499, 0, "期待しててくださいね！\nシェフィちゃんとあなたに\n『おいちー！』って喜んでもらえる\n最高のごちそうを準備しますから☆", 105801, "ペコリーヌ", 80005, 14, 0, "", 41, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (500, 0, "ええと…その…うーんと…\nわ、分かったわ\n私も【美食殿】の一員だもの", 106401, "シェフィ", 80005, 14, 0, "", 41, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (501, 0, "それにあなたも一緒みたいだし\n最後までがんばってみるわ…！", 106401, "シェフィ", 80005, 14, 0, "", 42, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (502, 0, "それではいつものあれを\nやりましょう！\n準備はいいですかっ？\n…いっきますよー！", 105801, "ペコリーヌ", 80005, 15, 0, "", 42, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (503, 0, "祝！", 106001, "キャル", 80005, 15, 0, "", 42, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (504, 0, "3.5周年！", 105901, "コッコロ", 80005, 15, 0, "", 38, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (505, 0, "おめでとうございます！", 106401, "シェフィ", 80005, 15, 0, "", 43, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (506, 0, "この日を迎えられたのも\nあなたが『プリンセスコネクト！\nRe:Dive』を遊んでくれている\nおかげです！", 190801, "カリン", 80005, 15, 0, "", 14, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (507, 0, "ということで\nみなさんからあなたへ一言ずつ\n感謝の言葉をどうぞ！", 190801, "カリン", 80005, 15, 0, "", 15, 0, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (508, 0, "感謝の言葉ですか？　わたしは\n毎日あなたに感謝してますよ\n【美食殿】の仲間になってくれて…\n一緒にごはんを食べてくれて…", 105801, "ペコリーヌ", 80005, 15, 0, "", 43, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (509, 0, "なにより今でもわたしをぺコリーヌ\nって呼んでくれてありがとうござい\nます。これからもわたしはあなたの\nぺコリーヌです！　やばいですね☆", 105801, "ペコリーヌ", 80005, 15, 0, "", 44, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (510, 0, "えっ！？　今度はあたし！？\n感謝って…まぁ、そうね…\nあんたにはあたしが\n辛くて苦しい時に助けてもらって…", 106001, "キャル", 80005, 15, 0, "", 43, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (511, 0, "でもおかげで色々吹っ切れたわ！\nもしあんたが困ってたら今度は\nあたしが助けてあげるから\nその時はちゃんと言いなさいよ！", 106001, "キャル", 80005, 15, 0, "", 44, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (512, 0, "ええと…次は私ね\n実はよく覚えてないのだけど\n空から落ちてきた私を受け止めて\nくれたのはあなたなのでしょう？", 106401, "シェフィ", 80005, 15, 0, "", 44, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (513, 0, "最初に私を見つけてくれたのが\nあなたで良かったって思ってるの\nおかげで私は居場所を見つけたから\nあなたがくれたもの、大切にするわ", 106401, "シェフィ", 80005, 15, 0, "", 45, 0, 0);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (514, 0, "では最後にわたくしから…\nわたくしは主さまの元を離れた日…\nこのように記念日をお祝いする\nことは二度とないと思っていました", 105901, "コッコロ", 80005, 15, 0, "", 39, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (515, 0, "ですが、主さまはわたくしを\n迎えにきてくださり、今もこうして\nおそばにおいてくださっています\nわたくしにとって毎日が記念日です", 105901, "コッコロ", 80005, 15, 0, "", 40, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (516, 0, "わたくしたちの物語は\nまだ続いていきます\nこれからも一緒にページを\n作っていきましょうね", 105901, "コッコロ", 80005, 15, 0, "", 41, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (517, 0, "それじゃ\nいつものあれでしめますよ！\nみんなで一緒に、さんはい☆", 105801, "ペコリーヌ", 80005, 15, 0, "", 45, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (518, 0, "これからも\nよろしくおねがいします！", 105801, "みんな", 80005, 15, 1, "105901,42,106001,45,106401,46,190801,16", 46, 0, 4);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (519, 1, "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 190804, "カリン", 60003, 0, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (520, 1, "今日の運勢は姫吉！　どんな不可能も可能にできちゃう！　　　　仲間と食卓を囲めばさらに運気上昇よ！　ただし魔物料理以外！", 0, "", 60003, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (521, 1, "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 0, "", 60003, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (522, 1, "今日の運勢は姫吉！　羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！　やってみましょう！", 0, "", 60003, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (523, 1, "今日の運勢は姫吉！　精霊も新年の幸福をお祝いしています！　　主さまの笑顔が見られて、わたくしも幸せいっぱいでございます♪", 0, "", 60003, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (524, 2, "今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", 0, "", 60003, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (525, 1, "今日の運勢は大吉！　お裁縫好きな女の子のお墨付きです！　　　お世話したがりの妹にめいっぱい愛されちゃうかも！？", 0, "", 60003, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (526, 1, "今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", 0, "", 60003, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (527, 1, "今日の運勢は大吉！　ラッキーカラーは鮮やかな黄色！　　　　　さらにシマシマのアイテムを持つと、運気倍増らしいッスよ♪", 0, "", 60003, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (528, 1, "今日の運勢は大吉！　秘められた力が開花するでしょう！　　　　じゃあ、私の龍眼と力比べしてみようか？　ふふ、冗談だよ～", 0, "", 60003, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (529, 2, "今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", 0, "", 60003, 0, 0, "", 0, 2, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (530, 1, "今日の運勢は中吉！　家の中でゆっくり過ごすのがよさそう！　　ラッキーアイテムはゲームよ！　ベストスコアを更新できるかも？", 0, "", 60003, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (531, 1, "今日の運勢は中吉！　上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？", 0, "", 60003, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (532, 1, "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 0, "", 60003, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (533, 1, "今日の運勢は中吉！　日頃の努力が報われます！　　　　　　　　親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。", 0, "", 60003, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (534, 1, "今日の運勢は中吉！　ラッキーアイテムはかわいいもの！　　　　ア、アタシはかわいいじゃなくてキレイだってば！　も～っ！", 0, "", 60003, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (535, 1, "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 0, "", 60003, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (536, 2, "今日の運勢は中吉！　悩まず行動すれば強運に恵まれる！　　　　守るよりも攻めるが吉だ！　勝負事をするにはいい運勢だな！", 0, "", 60003, 0, 0, "", 0, 3, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (537, 1, "今日の運勢は小吉！　まだ見ぬ危険が隠れているかも！　　　　　でも安心しろ！　提督が貴公を守ってくれるはずだぞ！", 0, "", 60003, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (538, 1, "今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", 0, "", 60003, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (539, 1, "今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", 0, "", 60003, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (540, 1, "今日の運勢は小吉！　難しい頼み事をされるかもしれません！　　うまくやれればきっと成長につながります、挑戦してみましょう！", 0, "", 60003, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (541, 1, "今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", 0, "", 60003, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (542, 1, "今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", 0, "", 60003, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (543, 2, "今日の運勢は小吉！　無理は禁物、お家で静かにしていましょう　プロぼっちの私が、お家での過ごし方……教えてあげましょうか？", 0, "", 60003, 0, 0, "", 0, 4, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (544, 0, "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 190804, "カリン", 60003, 0, 0, "", 2, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (545, 0, "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 190804, "カリン", 60003, 7, 0, "", 3, 0, 3);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (546, 1, "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 190804, "カリン", 60004, 0, 0, "", 1, 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (547, 1, "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 0, "", 60004, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (548, 1, "今日の運勢は姫吉！　羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！　やってみましょう！", 0, "", 60004, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (549, 1, "今日の運勢は姫吉！　宴でも開きたくなるほどの絶対幸運！\nイメチェンでもしてみるのはどうだ？　ぴょんぴょん、なんてな♪", 0, "", 60004, 0, 0, "", 0, 1, 2);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (550, 1, "今日の運勢は姫吉！　ずっと祈り続けていた願いが叶うかも！\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に", 0, "", 60004, 0, 0, "", 0, 1, 2);
